SELECT t.*
FROM ticket t
WHERE t.deleted = 0

    AND t.creator_id = #{currentUserId}



    AND t.status NOT IN ('completed', 'closed', 'rejected')
    AND (
        t.assignee_id = #{currentUserId}
        OR t.id IN (
            SELECT ta.ticket_id FROM ticket_assignee ta
            WHERE ta.user_id = #{currentUserId} AND ta.deleted = 0
        )
        OR (t.creator_id = #{currentUserId} AND t.assignee_id IS NULL)
    )


    AND (t.id IN (
            SELECT DISTINCT tl.ticket_id FROM ticket_log tl
            WHERE tl.user_id = #{currentUserId} AND tl.deleted = 0
         )
         OR t.id IN (
             SELECT ta.ticket_id FROM ticket_assignee ta
             WHERE ta.user_id = #{currentUserId} AND ta.deleted = 0
         ))


    AND t.id IN (
        SELECT tf.ticket_id FROM ticket_follower tf
        WHERE tf.user_id = #{currentUserId} AND tf.deleted = 0
    )



        AND (t.ticket_no LIKE CONCAT('%', #{keyword}, '%') OR t.title LIKE CONCAT('%', #{keyword}, '%'))



            AND t.ticket_no LIKE CONCAT('%', #{ticketNo}, '%')


            AND t.title LIKE CONCAT('%', #{title}, '%')




    AND t.category_id = #{categoryId}


    AND t.status = #{status}


    AND t.priority = #{priority}


    AND t.creator_id = #{creatorId}


    AND t.assignee_id = #{assigneeId}


    AND t.create_time >= #{createTimeStart}


    AND t.create_time <= #{createTimeEnd}



        ORDER BY FIELD(t.priority, 'urgent', 'high', 'medium', 'low')
         ASC
         DESC


        ORDER BY t.update_time
         ASC
         DESC


        ORDER BY t.create_time
         ASC
         DESC

SELECT t.assignee_id AS userId, COUNT(*) AS activeCount FROM ticket t WHERE t.deleted = 0 AND t.assignee_id IN
#{uid}
AND t.status NOT IN
#{s}
GROUP BY t.assignee_id
